# tests/integration/test_tool_invocation.py
import json
import pytest
import respx
import httpx
from myagent.agent import AgentStep

TOOL_CALL_RESPONSE = {
    "id": "chatcmpl-test123",
    "object": "chat.completion",
    "choices": [{
        "index": 0,
        "message": {
            "role": "assistant",
            "content": None,
            "tool_calls": [{
                "id": "call_abc",
                "type": "function",
                "function": {
                    "name": "search",
                    "arguments": "{"query": "IPCC sea level rise findings"}"
                }
            }]
        },
        "finish_reason": "tool_calls"
    }],
    "usage": {"prompt_tokens": 150, "completion_tokens": 30, "total_tokens": 180}
}

@pytest.mark.asyncio
@respx.mock
async def test_agent_step_invokes_search_tool(integration_config):
    respx.post("https://api.openai.com/v1/chat/completions").mock(
        return_value=httpx.Response(200, json=TOOL_CALL_RESPONSE)
    )

    step = AgentStep(config=integration_config)
    result = await step.run(
        messages=[{"role": "user", "content": "What are IPCC sea level rise findings?"}]
    )

    assert result.tool_calls is not None
    assert len(result.tool_calls) == 1
    assert result.tool_calls[0]["name"] == "search"
    args = json.loads(result.tool_calls[0]["arguments"])
    assert "query" in args
    assert isinstance(args["query"], str)
    assert len(args["query"]) > 0
